-- TopicRelations (PREREQUISITE + NEXT chain)

INSERT OR IGNORE INTO TopicRelations (topic_id, related_topic_id, relation_type, description_pl, description_ua, display_order, is_active)
SELECT src.id, tgt.id, 'NEXT', 'Następny temat wg spisu treści podręcznika.', 'Настępna temat zгідно зі змістом підручника.', 1, 1
FROM Topics src, Topics tgt
WHERE src.code = 'HIST5-PRE-001' AND tgt.code = 'HIST5-PRE-002'
  AND NOT EXISTS (
    SELECT 1 FROM TopicRelations tr
    WHERE tr.topic_id = src.id AND tr.related_topic_id = tgt.id AND tr.relation_type = 'NEXT'
  );

INSERT OR IGNORE INTO TopicRelations (topic_id, related_topic_id, relation_type, description_pl, description_ua, display_order, is_active)
